PART = '1><p class=muted>${e(s.source||\'unknown\')}</p></div><div><p class="val ${c(s.change_pct)}">${m(s.price,s.currency||M.base_currency)}</p><p class="${c(s.change_pct)}">${p(s.change_pct)}</p></div></div></div><div class=card><h2>${L==\'zh\'?\'AI 分析摘要\':\'AI Analyst Brief\'}</h2><p>${e(s.ai_commentary||R.overall_status||D().none)}</p></div><div class="grid c3"><div class=card><h2>${L==\'zh\'?\'基本面矩阵\':\'Fundamental Matrix\'}</h2><p class=muted>Cost ${m(s.cost,s.currency||M.base_currency)}<br>52W High ${m(s.high_52w,s.currency||M.base_currency)}<br>52W Low ${m(s.low_52w,s.currency||M.base_currency)}</p></div><div class=card><h2>${L==\'zh\'?\'技术指标\':\'Technical Indicators\'}</h2><p class=muted>MA5 ${s.indicators?.ma5??\'N/A\'}<br>MA20 ${s.indicators?.ma20??\'N/A\'}<br>5D ${p(s.indicators?.change_5d_pct)}</p></div><div class=card><h2>${L==\'zh\'?\'数据来源\':\'Data Sources\'}</h2><p class=muted>yfinance / akshare<br>Google News RSS / Bing<br>Google Sheet</p></div></div>`;aside.innerHTML=`<div class=card><h2>AI Confidence</h2><div class=score style="--p:${cf}%"><span>${cf}</span></div></div><div class=card><h2>${L==\'zh\'?\'风险\':\'Risk\'}</h2><span class="pill ${s.computed_risk_level||\'low\'}">${e(s.computed_risk_level||\'low\')}</span></div><div class=card><h2>${L==\'zh\'?\'智能新闻\':\'Smart News\'}</h2><div class=grid>${ns}</div></div>`}function feedF(){let I=S.flatMap(s=>(s.news||[]).map(n=>({...n,ticker:s.ticker}))).slice(0,12);feed.innerHTML=I.map(n=>`<div class=item><div class=row><a target=_blank href="${e(n.url)}"><b>${e(n.ticker)} | ${e(n.title)}</b></a><span class=pill>${e(n.sentiment||\'neutral\')}</span></div><p class=muted>${e(n.source)} | ${e(n.published_at)}</p></div>`).join(\'\')||`<div class=empty>${D().newsMiss}</div>`}langZh.onclick=()=>{L=\'zh\';lang()};langEn.onclick=()=>{L=\'en\';lang()};themeToggle.onclick=()=>{T=T==\'dark\'?\'light\':\'dark\';theme()};q.oninput=x=>{F.q=x.target.value;sq.value=F.q;assetsF();go(\'assets\')};sq.oninput=x=>{F.q=x.target.value;assetsF()};mf.onchange=x=>{F.m=x.target.value;assetsF()};tf.onchange=x=>{F.t=x.target.value;assetsF()};rf.onchange=x=>{F.r=x.target.value;assetsF()};reset.onclick=()=>{F={q:\'\',m:\'ALL\',t:\'ALL\',r:\'ALL\'};sq.value=\'\';mf.value=tf.value=rf.value=\'ALL\';assetsF()};pick.onchange=x=>{sel=x.target.value;deep()};copy.onclick=async()=>{try{await navigator.clipboard.writeText(R.summary_for_push||\'\')}catch{alert(R.summary_for_push||D().none)}};json.onclick=()=>{let a=document.createElement(\'a\');a.href=URL.createObjectURL(new Blob([JSON.stringify(R,null,2)],{type:\'application/json\'}));a.download=\'latest_report.json\';a.click()};back.onclick=()=>alert(L==\'zh\'?\'回测完成：当前离线报告仅展示模拟结果，不执行交易。\':\'Backtest completed. This offline report only displays simulated results and does not execute trades.\');theme();lang();\n</script></body></html>'
